import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 施無畏印, 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 彌勒菩薩 = (bi) => 菩薩坐身(bi, {
    月輪: false,
    嚴先: true,
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：執蓮莖，蓮上安水瓶（莖蓮先落，瓶立其上，拳覆莖）
        衣(() => {
            M(-6.5, 41.6);
            C(-6.2, 38.8, -6.0, 36.2, -5.9, 33.9);
            S();
            M(-7.2, 41.5);
            C(-6.95, 38.8, -6.85, 36.2, -6.8, 33.9);
            S();
            M(-4.5, 33.9);
            Qk(-5.1, 32.5, -5.9, 32.1);
            S();
            M(-8.2, 33.85);
            Qk(-7.7, 32.55, -6.95, 32.1);
            S();
            M(-5.9, 32.1);
            Qk(-6.4, 31.9, -6.95, 32.1);
            S();
            // 水瓶：鼓腹細頸口緣微張
            M(-7.15, 31.75);
            C(-7.5, 30.8, -7.3, 29.9, -6.85, 29.55);
            S();
            M(-5.55, 31.75);
            C(-5.2, 30.8, -5.4, 29.9, -5.85, 29.55);
            S();
            M(-6.85, 29.55);
            L(-6.9, 28.85);
            S();
            M(-5.85, 29.55);
            L(-5.8, 28.85);
            S();
            M(-7.2, 28.8);
            Qk(-6.35, 28.5, -5.5, 28.8);
            S();
            M(-7.15, 31.8);
            Qk(-6.35, 32.15, -5.55, 31.8);
            S();
            細(() => { M(-6.9, 30.5); Qk(-6.35, 30.75, -5.8, 30.5); S(); });
        });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.8, 40.3], [-8.8, 41.9], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.35, 肘帽: true })));
        側拳(bi, -6.8, 41.6, 0.25, 1.06);
        // 尊左：施無畏——舉掌當胸向外
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [6.4, 37.2], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        施無畏印(bi, 5.2, 33.2, 0.62, false);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-9.8, 40.8, -9.3, 41.9, -9.8, 43.1], [-10.7, 41.0, -10.2, 42.1, -10.7, 43.3]], [-10.4, 42.1]);
            腕釧(bi, [[7.4, 36.5, 6.7, 37.3, 6.0, 38.1], [6.9, 35.9, 6.2, 36.7, 5.5, 37.5]], [6.5, 36.9]);
        });
    },
});
